/**
 * Render the clusters inventory view with per-cluster object tables.
 */
function renderClusters() {
    const el = document.getElementById('view-clusters');
    if (M.clusters.length === 0) {
        el.innerHTML = '<p style="color:var(--text-muted)">No clusters in project.</p>';
        return;
    }

    let html = '<h1 style="margin-bottom:20px">Clusters</h1>';
    M.clusters.forEach(c => {
        html += '<div class="cluster-card">';
        html += '<h3>' + escapeHtml(c.name) + '</h3>';
        html += '<div class="cluster-stats">';
        if (c.size) html += '<span>Size: ' + escapeHtml(c.size) + '</span>';
        if (c.replication_factor != null) html += '<span>RF: ' + c.replication_factor + '</span>';
        html += '<span>' + c.object_ids.length + ' objects</span><span>' + c.index_count + ' indexes</span></div>';

        if (c.object_ids.length > 0) {
            html += '<table class="data-table"><thead><tr><th>Object</th><th>Type</th></tr></thead><tbody>';
            c.object_ids.forEach(oid => {
                const o = objMap[oid];
                if (!o) return;
                html += '<tr><td><a class="dep-link" data-id="' + escapeHtml(oid) + '">' + escapeHtml(oid) + '</a></td>';
                html += '<td>' + escapeHtml(o.object_type) + '</td></tr>';
            });
            html += '</tbody></table>';
        }
        html += '</div>';
    });

    el.innerHTML = html;
    el.querySelectorAll('.dep-link').forEach(l => {
        l.addEventListener('click', () => navigate('detail', l.dataset.id));
    });
}

